var HeadlessPromptError=class extends Error{promptMessage;constructor(e){super(`Headless run needs every decision up front, but the flow tried to ask: "${e}". Provide the matching flag (--model, --channels, --skip-vercel, --project, --team, --gateway-api-key, --chat) and re-run.`),this.name=`HeadlessPromptError`,this.promptMessage=e}};function createHeadlessPrompter(e){let fail=e=>{throw new HeadlessPromptError(e)};async function select(e){return fail(e.message)}return{text:async e=>fail(e.message),password:async e=>fail(e.message),select,note:t=>e(t),intro:(t,n)=>e(n?`${t}: ${n}`:t),outro:t=>e(t),log:{message:t=>e(t),info:t=>e(t),success:t=>e(t),warning:t=>e(t),error:t=>e(t),commandOutput:t=>e(t)}}}function formatHeadlessEvent(e){return JSON.stringify(e)}export{HeadlessPromptError,createHeadlessPrompter,formatHeadlessEvent};